package aula_02_operadores;

public class Operadores_Unarios {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int contador = 1000;
		
		System.out.println("Valor inicial de contador: " + contador);
		
		//System.out.println("Valor Pré Incremento: " + (++contador));
		
		System.out.println("Valor Pós Incremento: " + (contador++));
		
		System.out.println("Novo Valor de Incremento: " + contador);
		

	}

}
